import{_ as a,o,c as e,O as i}from"./chunks/framework.bdcb0ee1.js";const p=JSON.parse('{"title":"Custom Domains","description":"","frontmatter":{},"headers":[],"relativePath":"administration/forumspark/custom-domains.md","filePath":"administration/forumspark/custom-domains.md","lastUpdated":1773167007000}'),t={name:"administration/forumspark/custom-domains.md"},r=i('<h1 id="custom-domains" tabindex="-1">Custom Domains <a class="header-anchor" href="#custom-domains" aria-label="Permalink to &quot;Custom Domains&quot;">​</a></h1><p>ForumSpark allows you to connect your own domain name to your forum board. Instead of using the default <code>yourboard.forumspark.net</code> address, you can serve your forum from a domain like <code>forum.example.com</code>.</p><p>You can manage custom domains from the <strong>ForumSpark</strong> section in the Admin Control Panel.</p><nav class="table-of-contents"><ul><li><a href="#adding-a-domain">Adding a Domain</a></li><li><a href="#setting-up-dns">Setting Up DNS</a></li><li><a href="#verification">Verification</a></li><li><a href="#primary-domain">Primary Domain</a></li><li><a href="#removing-a-domain">Removing a Domain</a></li><li><a href="#notes">Notes</a></li></ul></nav><h2 id="adding-a-domain" tabindex="-1">Adding a Domain <a class="header-anchor" href="#adding-a-domain" aria-label="Permalink to &quot;Adding a Domain&quot;">​</a></h2><p>To add a custom domain, go to <strong>ForumSpark &gt; Domain Manager</strong> and enter your domain name.</p><p>The domain must be a valid fully qualified domain name. For example:</p><ul><li><code>forum.example.com</code></li><li><code>community.mysite.org</code></li><li><code>example.com</code></li></ul><img width="1946" height="744" alt="image" src="https://github.com/user-attachments/assets/b0639959-b525-4225-833a-742a6881809c"><h2 id="setting-up-dns" tabindex="-1">Setting Up DNS <a class="header-anchor" href="#setting-up-dns" aria-label="Permalink to &quot;Setting Up DNS&quot;">​</a></h2><p>Before your domain can be verified, you need to create a <strong>CNAME record</strong> with your domain provider that points to the ForumSpark infrastructure.</p><ol><li>Log in to your domain registrar or DNS provider.</li><li>Create a new <strong>CNAME</strong> record for your domain.</li><li>Set the target/value to the address shown in the Admin CP.</li><li>Save the record and wait for DNS propagation (this can take up to 48 hours, but is usually much faster).</li></ol><blockquote><p>Note: DNS changes can take time to propagate. If verification fails initially, try again after a few minutes.</p></blockquote><h2 id="verification" tabindex="-1">Verification <a class="header-anchor" href="#verification" aria-label="Permalink to &quot;Verification&quot;">​</a></h2><p>After adding a domain, ForumSpark will automatically attempt to verify it by checking the CNAME record. The verification process runs shortly after the domain is added.</p><ul><li><strong>Pending</strong>: The domain has been added but is not yet verified.</li><li><strong>Verified</strong>: The CNAME record has been confirmed and the domain is ready to use.</li></ul><p>If verification fails, check that your CNAME record is correctly configured and try again.</p><h2 id="primary-domain" tabindex="-1">Primary Domain <a class="header-anchor" href="#primary-domain" aria-label="Permalink to &quot;Primary Domain&quot;">​</a></h2><p>Once a domain is verified, you can set it as your board&#39;s <strong>primary domain</strong>. The primary domain is the address that ForumSpark will use as the canonical URL for your board.</p><p>If no custom domain is configured, your board will continue to be accessible via the default <code>yourboard.forumspark.net</code> address.</p><h2 id="removing-a-domain" tabindex="-1">Removing a Domain <a class="header-anchor" href="#removing-a-domain" aria-label="Permalink to &quot;Removing a Domain&quot;">​</a></h2><p>You can delete a custom domain at any time from the Domain Manager. However, you cannot delete the domain you are currently accessing the board through.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>You can add multiple custom domains to your board.</li><li>Only verified domains can be set as the primary domain.</li><li>SSL certificates are provisioned automatically for verified custom domains.</li><li>If you remove your primary custom domain, the board will fall back to the default ForumSpark subdomain.</li></ul>',24),n=[r];function d(s,m,l,c,u,h){return o(),e("div",null,n)}const g=a(t,[["render",d]]);export{p as __pageData,g as default};
